This is a code example:

var items = new List<IUddTypeFormat>();
foreach (var uddEntry in ((IStringParsedMetadataGetData)this).GetUddTokens())
{
    var uddWriter = Base.ServiceStore<IDatalogService>.Service.GetItuffUddTypeWriter();
    uddWriter.SetData(uddEntry.Item1, uddEntry.Item2);
    items.Add(uddWriter);
}
if (items.Count != 0)
{
    Base.ServiceStore<IDatalogService>.Service.AddUddTokens(this.CurrentInstanceName, items);
}


