This is a code example:

var ituffWriter = Base.ServiceStore<IDatalogService>.Service.GetItuffComntWriter();
ituffWriter.SetData($"Comment");
bool makeItuffDataQueriable = true;
Base.ServiceStore<IDatalogService>.Service.WriteToItuff(ituffWriter, makeItuffDataQueriable, sessionContext);
var tname = ituffWriter.GetTName();
var ituff = ServiceStore<IDatalogService>.Service.GetItuffSnippetForTname(tname);
if(ituff == "ItuffSnippetNoDataValue")
{
    Prime.Base.ServiceStore<IConsoleService>.Service.Print($"Ituff data for instance {tname}: \n {ituff}.");
}


