var listOfDatalogInfo = new List<IDatalogFormatBase>();
foreach (var data in datalogInfo)
{
var writer = Base.ServiceStore<IDatalogService>.Service.GetItuffStrgaltWriter();
writer.SetData("fus_msbF", data.Value);
listOfDatalogInfo.Add(writer);
}
bool makeItuffDataQueriable = true;
foreach (var data in datalogInfo)
{
Base.ServiceStore<IDatalogService>.Service.WriteToItuff(listOfDatalogInfo, makeItuffDataQueriable, sessionContext);
var tname = data.GetTName();
var ituff = ServiceStore<IDatalogService>.Service.GetItuffSnippetForTname(tname);
if(ituff == "ItuffSnippetNoDataValue")
{
    Prime.Base.ServiceStore<IConsoleService>.Service.Print($"Ituff data for instance {tname}: \n {ituff}.");
}
}


