This is a code example:

var currentEndDeviceTimeStamp = DateTime.Now.ToString("yyyyMMddHHmmss");
const string userBinPrefix = "9098";
var ituff = new List<IDatalogFormatBase>();
var ituffComntWriter = Base.ServiceStore<IDatalogService>.Service.GetItuffComntWriter();
ituffComntWriter.SetData("footer_begin");
ituff.Add(ituffComntWriter);
var ituffEndOfDeviceWriter = Base.ServiceStore<IDatalogService>.Service.GetItuffEndOfDeviceWriter();
ituffEndOfDeviceWriter.SetData(currentEndDeviceTimeStamp, $"{userBinPrefix}{datalogUserBin}", datalogUserBin, datalogUserBin.Substring(0, 2), "fail");
ituff.Add(ituffEndOfDeviceWriter);
Base.ServiceStore<IDatalogService>.Service.WriteToItuff(ituff, this.sessionContext);
Base.ServiceStore<IDatalogService>.Service.FlushAllDataStreamLogs(this.sessionContext);


